const historico = $input.all().map(i => i.json).filter(i => i.role);
const chatInput = $('Execute Workflow Trigger').first().json.chatInput ?? 
                  $('Execute Workflow Trigger').first().json.query ?? '';

const messages = historico.map(msg => ({
  role: msg.role,
  content: msg.content
}));

return {
  session_id: $('Upsert Sessao').first().json.id,
  messages: messages,
  chatInput: chatInput
};
